28: /**
29:  * A helper class for managing the heartbeat to the coordinator
30:  */
31: public final class Heartbeat {
32:     private final int maxPollIntervalMs;
33:     private final GroupRebalanceConfig rebalanceConfig;
34:     private final Time time;
35:     private final Timer heartbeatTimer;
36:     private final Timer sessionTimer;
37:     private final Timer pollTimer;
38:     private final Logger log;
39:     private final ExponentialBackoff retryBackoff;
40: 
41:     private volatile long lastHeartbeatSend = 0L;
42:     private volatile boolean heartbeatInFlight = false;
43:     private volatile long heartbeatAttempts = 0L;
44: 
45:     public Heartbeat(GroupRebalanceConfig config,
46:                      Time time) {
47:         if (config.heartbeatIntervalMs >= config.sessionTimeoutMs)
48:             throw new IllegalArgumentException("Heartbeat must be set lower than the session timeout");
49:         this.rebalanceConfig = config;
50:         this.time = time;
51:         this.heartbeatTimer = time.timer(config.heartbeatIntervalMs);
52:         this.sessionTimer = time.timer(config.sessionTimeoutMs);
53:         this.maxPollIntervalMs = config.rebalanceTimeoutMs;
54:         this.pollTimer = time.timer(maxPollIntervalMs);
55:         this.retryBackoff = new ExponentialBackoff(rebalanceConfig.retryBackoffMs,
56:                 CommonClientConfigs.RETRY_BACKOFF_EXP_BASE,
57:                 rebalanceConfig.retryBackoffMaxMs,
58:                 CommonClientConfigs.RETRY_BACKOFF_JITTER);
59: 
60:         final LogContext logContext = new LogContext("[Heartbeat groupID=" + config.groupId + "] ");
61:         this.log = logContext.logger(getClass());
62:     }
63: 
64:     private void update(long now) {
65:         heartbeatTimer.update(now);
66:         sessionTimer.update(now);
67:         pollTimer.update(now);
68:     }
69: 
70:     public void poll(long now) {
71:         update(now);
72:         pollTimer.reset(maxPollIntervalMs);
73:     }
74: 
75:     boolean hasInflight() {
76:         return heartbeatInFlight;
77:     }
78: 
79:     void sentHeartbeat(long now) {
80:         lastHeartbeatSend = now;
81:         heartbeatInFlight = true;
82:         update(now);
83:         heartbeatTimer.reset(rebalanceConfig.heartbeatIntervalMs);
84: 
85:         if (log.isTraceEnabled()) {
86:             log.trace("Sending heartbeat request with {}ms remaining on timer", heartbeatTimer.remainingMs());
87:         }
88:     }
89: 
90:     void failHeartbeat() {
91:         update(time.milliseconds());
92:         heartbeatInFlight = false;
93:         heartbeatTimer.reset(retryBackoff.backoff(heartbeatAttempts++));
94: 
95:         log.trace("Heartbeat failed, reset the timer to {}ms remaining", heartbeatTimer.remainingMs());
96:     }
97: 
98:     void receiveHeartbeat() {
99:         update(time.milliseconds());
100:         heartbeatInFlight = false;
101:         heartbeatAttempts = 0L;
102:         sessionTimer.reset(rebalanceConfig.sessionTimeoutMs);
103:     }
104: 
105:     boolean shouldHeartbeat(long now) {
106:         update(now);
107:         return heartbeatTimer.isExpired();
108:     }
109:     
110:     long lastHeartbeatSend() {
111:         return this.lastHeartbeatSend;
112:     }
113: 
114:     long timeToNextHeartbeat(long now) {
115:         update(now);
116:         return heartbeatTimer.remainingMs();
117:     }
118: 
119:     boolean sessionTimeoutExpired(long now) {
120:         update(now);
121:         return sessionTimer.isExpired();
122:     }
123: 
124:     void resetTimeouts() {
125:         update(time.milliseconds());
126:         sessionTimer.reset(rebalanceConfig.sessionTimeoutMs);
127:         pollTimer.reset(maxPollIntervalMs);
128:         heartbeatTimer.reset(rebalanceConfig.heartbeatIntervalMs);
129:     }
130: 
131:     void resetSessionTimeout() {
132:         update(time.milliseconds());
133:         sessionTimer.reset(rebalanceConfig.sessionTimeoutMs);
134:     }
135: 
136:     boolean pollTimeoutExpired(long now) {
137:         update(now);
138:         return pollTimer.isExpired();
139:     }
140: 
141:     long lastPollTime() {
142:         return pollTimer.currentTimeMs();
143:     }
144: }
